        "question": [
          "How many UK customers there are in each status?"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "/* 1.2. ftd_funnel_uk - PlayerStatus */\n",
              "select\n",
              "  TBL.PlayerStatus,\n",
              "  count(TBL.CID) as count_users\n",
              "from\n",
              "  main.etoro_kpi.ftd_funnel_uk TBL\n",
              "where\n",
              "  TBL.CID not in (\n",
              "    select\n",
              "      CID\n",
              "    from\n",
              "      main.etoro_kpi.customer_exclude_list\n",
              "  )\n",
              "group by\n",
              "  TBL.PlayerStatus"
            ]
          }
        ]
      },
      {
        "id": "01f0f1f11e9f18aeb6515041bd43b298",
        "question": [
          "how many blocked and non-blocked users there are in the UK?"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "\n",
              "/* 1. ftd_funnel_uk - IsBlocked */ \n",
              "\n",
              "select TBL.IsBlocked, count (TBL.CID) as count_users\n",
              "from main.etoro_kpi.ftd_funnel_uk TBL\n",
              "where TBL.CID not in (select CID from main.etoro_kpi.customer_exclude_list)\n",
              "group by TBL.IsBlocked"
            ]
          }
        ]
      },
      {
        "id": "01f0ebc1091715a8860825ad2a8694b4",
        "question": [
          "show me the process of registration to ftd by country try to identify drop scenario during the process in each step"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "WITH funnel AS (\n",
              "  SELECT \n",
              "    v.Country,\n",
              "    COUNT(*) AS registered,\n",
              "    SUM(CASE WHEN v.IsVL0 = 1 THEN 1 ELSE 0 END) AS vl0,\n",
              "    SUM(CASE WHEN v.IsVL1 = 1 THEN 1 ELSE 0 END) AS vl1,\n",
              "    SUM(CASE WHEN v.IsVL2 = 1 THEN 1 ELSE 0 END) AS vl2,\n",
              "    SUM(CASE WHEN v.IsVL3 = 1 THEN 1 ELSE 0 END) AS vl3,\n",
              "    SUM(CASE WHEN v.IsFTD = 1 THEN 1 ELSE 0 END) AS ftd\n",
              "  FROM main.bi_output_stg.vg_acquisition_funnel v\n",
              "  LEFT JOIN main.etoro_kpi.customer_exclude_list e ON v.CID = e.CID\n",
              "  WHERE e.CID IS NULL AND v.Country IS NOT NULL\n",
              "  GROUP BY v.Country\n",
              ")\n",
              "SELECT \n",
              "  Country,\n",
              "  registered,\n",
              "  vl0,\n",
              "  registered - vl0 AS drop_after_registration,\n",
              "  vl1,\n",
              "  vl0 - vl1 AS drop_after_vl0,\n",
              "  vl2,\n",
              "  vl1 - vl2 AS drop_after_vl1,\n",
              "  vl3,\n",
              "  vl2 - vl3 AS drop_after_vl2,\n",
              "  ftd,\n",
              "  vl3 - ftd AS drop_after_vl3\n",
              "FROM funnel\n",
              "ORDER BY Country;"
            ]
          }
        ]
      }
    ]
